import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { EnvelopeIcon, LockClosedIcon, TicketIcon, UserCircleIcon, ShieldCheckIcon, UserGroupIcon } from '@heroicons/react/24/outline';

const Login = () => {
  const [formData, setFormData] = useState({
    email: '',
    password: '',
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [selectedRole, setSelectedRole] = useState('user');
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value,
    });
    setError('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    
    const result = await login(formData.email, formData.password);
    
    if (result.success) {
      navigate('/');
    } else {
      setError(result.error || 'Login failed');
    }
    
    setLoading(false);
  };

  const quickLogin = (email, password) => {
    setFormData({ email, password });
    setTimeout(() => {
      document.getElementById('login-form').dispatchEvent(new Event('submit', { cancelable: true, bubbles: true }));
    }, 100);
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-indigo-100 via-purple-50 to-pink-100 py-12 px-4 sm:px-6 lg:px-8">
      <div className="max-w-md w-full space-y-8 bg-white p-10 rounded-2xl shadow-2xl">
        <div className="text-center">
          <div className="flex justify-center">
            <TicketIcon className="h-12 w-12 text-indigo-600 animate-bounce" />
          </div>
          <h2 className="mt-6 text-3xl font-extrabold text-gray-900">
            Welcome to HelpDesk Pro
          </h2>
          <p className="mt-2 text-sm text-gray-600">
            Sign in to manage your tickets
          </p>
        </div>
        
        {error && (
          <div className="bg-red-50 border border-red-400 text-red-800 px-4 py-3 rounded-lg">
            <p className="text-sm">{error}</p>
          </div>
        )}
        
        <form id="login-form" className="mt-8 space-y-6" onSubmit={handleSubmit}>
          <div className="space-y-4">
            <div>
              <label htmlFor="email" className="block text-sm font-medium text-gray-700 mb-1">
                Email Address
              </label>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                  <EnvelopeIcon className="h-5 w-5 text-gray-400" />
                </div>
                <input
                  id="email"
                  name="email"
                  type="email"
                  autoComplete="email"
                  required
                  value={formData.email}
                  onChange={handleChange}
                  className="input-field pl-10"
                  placeholder="Enter your email"
                />
              </div>
            </div>
            
            <div>
              <label htmlFor="password" className="block text-sm font-medium text-gray-700 mb-1">
                Password
              </label>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                  <LockClosedIcon className="h-5 w-5 text-gray-400" />
                </div>
                <input
                  id="password"
                  name="password"
                  type="password"
                  autoComplete="current-password"
                  required
                  value={formData.password}
                  onChange={handleChange}
                  className="input-field pl-10"
                  placeholder="Enter your password"
                />
              </div>
            </div>
          </div>

          <div>
            <button
              type="submit"
              disabled={loading}
              className="btn-primary w-full flex justify-center items-center space-x-2"
            >
              {loading ? (
                <>
                  <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-white"></div>
                  <span>Signing in...</span>
                </>
              ) : (
                <span>Sign in</span>
              )}
            </button>
          </div>
        </form>

        {/* Quick Login Buttons */}
        <div className="mt-6">
          <p className="text-xs text-gray-500 text-center mb-3">Quick Login (Demo)</p>
          <div className="grid grid-cols-3 gap-2">
            <button
              onClick={() => quickLogin('user@example.com', '123456')}
              className="flex flex-col items-center p-2 bg-green-50 hover:bg-green-100 rounded-lg transition-all duration-200"
            >
              <UserCircleIcon className="h-6 w-6 text-green-600" />
              <span className="text-xs mt-1">Regular User</span>
            </button>
            <button
              onClick={() => quickLogin('agent@example.com', '123456')}
              className="flex flex-col items-center p-2 bg-blue-50 hover:bg-blue-100 rounded-lg transition-all duration-200"
            >
              <UserGroupIcon className="h-6 w-6 text-blue-600" />
              <span className="text-xs mt-1">Support Agent</span>
            </button>
            <button
              onClick={() => quickLogin('admin@example.com', '123456')}
              className="flex flex-col items-center p-2 bg-purple-50 hover:bg-purple-100 rounded-lg transition-all duration-200"
            >
              <ShieldCheckIcon className="h-6 w-6 text-purple-600" />
              <span className="text-xs mt-1">Administrator</span>
            </button>
          </div>
        </div>

        <div className="text-center">
          <p className="text-sm text-gray-600">
            Don't have an account?{' '}
            <Link to="/register" className="font-medium text-indigo-600 hover:text-indigo-500">
              Sign up here
            </Link>
          </p>
        </div>

        {/* Demo Credentials Info */}
        <div className="mt-4 p-4 bg-gray-50 rounded-lg">
          <p className="text-xs font-semibold text-gray-700 text-center mb-2">
            📝 Demo Accounts
          </p>
          <div className="space-y-1 text-xs text-gray-600">
            <p>👤 <strong>User:</strong> user@example.com / 123456</p>
            <p>🧑‍💻 <strong>Agent:</strong> agent@example.com / 123456</p>
            <p>👑 <strong>Admin:</strong> admin@example.com / 123456</p>
          </div>
          <p className="text-xs text-gray-500 text-center mt-2">
            💡 You can also register with your own email
          </p>
        </div>
      </div>
    </div>
  );
};

export default Login;
